function showAlert(e,o=null){return new Promise(n=>{closeModal();const t=document.createElement("div");t.className="modal-overlay";const l=document.createElement("div");l.className="modal_",l.innerHTML=`\n            ${e}\n            <button class="close-button">OK</button>\n        `,t.appendChild(l),document.body.appendChild(t),l.querySelector(".close-button").addEventListener("click",()=>{closeModal(),setTimeout(()=>{o&&o(),n()},0)})});function closeModal(){const e=document.querySelector(".modal-overlay");e&&e.remove()}}